+          return null;
+        }
+        return {
+          href,
+          number: Number(match[1]),
+        };
+      })
+      .filter(Boolean);
+
+    if (!issueLinks.length) {
+      return null;
+    }
+
+    return issueLinks.reduce((min, current) =>
+      current.number < min.number ? current : min
+    );
+  });
+
+  if (!oldestIssue) {
+    throw new Error("Could not find any open issue links on the list page.");
+  }
+
+  await page.goto(`https://github.com${oldestIssue.href}`, {
+    waitUntil: "domcontentloaded",
+  });
+
+  await page.waitForSelector("h1", { timeout: 30000 });
+
+  const extracted = await page.evaluate(() => {
+    const numberText =
+      document.querySelector("span.gh-header-number")?.textContent?.trim() || "";
+    const issueNumber = Number(numberText.replace("#", "").trim());
+
