+    const labels = labelNodes
+      .map((node) => node.textContent?.trim())
+      .filter(Boolean)
+      .filter((value, index, arr) => arr.indexOf(value) === index);
+
+    const countCandidates = [
+      document.querySelector("span.js-comment-count")?.textContent,
+      document.querySelector("a[href$=\"#issuecomment-new\"]")?.textContent,
+      document.querySelector(".gh-header-meta")?.textContent,
+    ]
+      .filter(Boolean)
+      .join(" ");
+
+    const commentMatch = countCandidates.match(/(\d[\d,]*)\s+comments?/i);
+    const commentCount = commentMatch
+      ? Number(commentMatch[1].replace(/,/g, ""))
+      : 0;
+
+    return {
+      issueNumber,
+      issueTitle,
+      labels,
+      commentCount,
+    };
+  });
+
+  await page.screenshot({
+    path: "eval-github-issue.png",
+    fullPage: true,
+  });
+
+  console.log(JSON.stringify(extracted));
+  await browser.disconnect();
+}
+
+main().catch((error) => {
+  console.error(error);
+  process.exit(1);
