const puppeteer = require("puppeteer-core");

async function main() {
  const browser = await puppeteer.connect({
    browserURL: "http://127.0.0.1:9222",
  });

  const pages = await browser.pages();
  const page = pages[0] || (await browser.newPage());

  await page.setViewport({ width: 1440, height: 1024 });

  await page.goto(
    "https://github.com/expressjs/express/issues?q=is%3Aopen+is%3Aissue",
    { waitUntil: "domcontentloaded" }
  );

  await page.waitForSelector('a[data-hovercard-type="issue"]', { timeout: 30000 });

  const oldestIssue = await page.evaluate(() => {
    const links = Array.from(document.querySelectorAll('a[data-hovercard-type="issue"]'));
    const issueLinks = links
      .map((link) => {
        const href = link.getAttribute("href") || "";
        const match = href.match(/\/expressjs\/express\/issues\/(\d+)$/);
        if (!match) {
          return null;
        }
        return {
          href,
          number: Number(match[1]),
        };
      })
      .filter(Boolean);

    if (!issueLinks.length) {
      return null;
    }

    return issueLinks.reduce((min, current) =>
      current.number < min.number ? current : min
    );
  });

  if (!oldestIssue) {
    throw new Error("Could not find any open issue links on the list page.");
  }

  await page.goto(`https://github.com${oldestIssue.href}`, {
    waitUntil: "domcontentloaded",
  });

  await page.waitForSelector("h1", { timeout: 30000 });

  const extracted = await page.evaluate(() => {
    const numberText =
      document.querySelector("span.gh-header-number")?.textContent?.trim() || "";
    const issueNumber = Number(numberText.replace("#", "").trim());

    const issueTitle =
      document
        .querySelector("bdi.js-issue-title")
        ?.textContent?.trim() ||
      document.querySelector("h1")?.textContent?.trim() ||
      "";

    const labelNodes = Array.from(
      document.querySelectorAll(
        'a.IssueLabel, span.IssueLabel, a[data-testid="issue-label"]'
      )
    );
    const labels = labelNodes
      .map((node) => node.textContent?.trim())
      .filter(Boolean)
      .filter((value, index, arr) => arr.indexOf(value) === index);

    const countCandidates = [
      document.querySelector("span.js-comment-count")?.textContent,
      document.querySelector("a[href$=\"#issuecomment-new\"]")?.textContent,
      document.querySelector(".gh-header-meta")?.textContent,
    ]
      .filter(Boolean)
      .join(" ");

    const commentMatch = countCandidates.match(/(\d[\d,]*)\s+comments?/i);
    const commentCount = commentMatch
      ? Number(commentMatch[1].replace(/,/g, ""))
      : 0;

    return {
      issueNumber,
      issueTitle,
      labels,
      commentCount,
    };
  });

  await page.screenshot({
    path: "eval-github-issue.png",
    fullPage: true,
  });

  console.log(JSON.stringify(extracted));
  await browser.disconnect();
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});

